import React from 'react'
import BlogPreview from './BlogPreview.jsx';
import {useEffect,useState,useContext} from 'react'
import { UserContext } from './UserContext.jsx';
const BlogList = () => {
  const [blogs,setBlogs]= useState([])
  const {userInfo} = useContext(UserContext) 
  const {appliedChanges} = useContext(UserContext) 
  useEffect(()=>{
    fetch('http://localhost:5000/blog'
    ).then(response=>{
      response.json().then(posts=>{
        setBlogs(posts)
      })
    })
  },[])

  const alertPlaceholder = document.getElementById('alertPlaceholder')
  
  const appendAlert = (type,message) => {
    const wrapper = document.createElement('div')
    wrapper.innerHTML = [
      `<div class="alert alert-${type} alert-dismissible" role="alert">`,
      `   <div>${message}.</div>`,
      '   <button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button>',
      '</div>'
    ].join('')

    alertPlaceholder.append(wrapper)
  }

  if(appliedChanges){
    appendAlert('success','Changes applied successfully')
    setTimeout(function() {
      alertPlaceholder.removeChild(alertPlaceholder.firstElementChild);
    },2000);
  }
  else if(userInfo){
    appendAlert('success',`Welcome ${userInfo.userName}`)
    setTimeout(function() {
      alertPlaceholder.removeChild(alertPlaceholder.firstElementChild);
    },2000);
  }
  
  return (
    <>
      <div className="alertPlaceholder"></div>
      {blogs.length>0 && 
        <div className="d-flex flex-column">
          {
            blogs.map(blog=>{
              return <BlogPreview {...blog} Key={blog._id}/>
            })
          }
        </div>
      
      }
    </>
  )
}

export default BlogList
